parameters.jsonBody:
={
  "urls": [
    "https://www.cushmanwakefield.com/en/united-states/insights/us-marketbeats/fort-myers-naples-marketbeats",
    "https://lsicompanies.com/market-reports",
    "https://cpswfl.com/market-reports/"
  ],
  "prompt": "Extract Southwest Florida commercial real estate market data: vacancy rate (percent, 0-100), net absorption (square feet), average asking rent (USD per square foot, NNN), reporting submarket name. Return one record per submarket. Quarter should be the reporting quarter formatted YYYY-QN (e.g. 2026-Q3). Use null if a value is not present — never invent.",
  "schema": {
    "type": "object",
    "properties": {
      "rows": {
        "type": "array",
        "items": {
          "type": "object",
          "required": ["submarket", "quarter"],
          "properties": {
            "submarket":       { "type": "string" },
            "quarter":         { "type": "string", "pattern": "^\\d{4}-Q[1-4]$" },
            "vacancy_rate":    { "type": ["number", "null"] },
            "asking_rent_nnn": { "type": ["number", "null"] },
            "absorption_sqft": { "type": ["number", "null"] },
            "source_url":      { "type": ["string", "null"] }
          }
        }
      }
    }
  },
  "model": "spark-1-mini",
  "maxCredits": 1000
}

parameters.jsCode:
// Firecrawl /v2/agent returns { success, data: { result, sources } }.
// The agent's structured output is in `data.result.rows` per our schema.
const out = [];
for (const item of items) {
  const root = item.json?.data?.result ?? item.json?.result ?? item.json;
  const rows = Array.isArray(root?.rows) ? root.rows : (Array.isArray(root) ? root : []);
  for (const r of rows) {
    out.push({ json: r });
  }
}
return out;

// Per the 2026-05-25 firecrawl-pipeline-skeleton plan: halt-and-alert on
// the first range violation. n8n's top-level error workflow (Settings →
// Error Workflow) catches the throw and routes to Slack — no silent
// quarantine, no Postgres write.
const RANGES = {
  vacancy_rate:    { min: 1,         max: 40        },
  asking_rent_nnn: { min: 8,         max: 80        },
  absorption_sqft: { min: -600000,   max: 600000    }
};
for (const item of items) {
  const row = item.json;
  if (!row.submarket || typeof row.submarket !== 'string') {
    throw new Error(`Missing submarket on row: ${JSON.stringify(row)}`);
  }
  if (!row.quarter || !/^\d{4}-Q[1-4]$/.test(row.quarter)) {
    throw new Error(`Invalid quarter "${row.quarter}" on submarket "${row.submarket}" — expected YYYY-QN.`);
  }
  for (const [field, { min, max }] of Object.entries(RANGES)) {
    const v = row[field];
    if (v != null && (v < min || v > max)) {
      throw new Error(
        `Range violation: ${field}=${v} on "${row.submarket}" (allowed ${min}..${max}).`
      );
    }
  }
  row._ingested_at = new Date().toISOString();
  row.verified = false;            // manual spot-check gate
  row._source_model = 'spark-1-mini';
  row.id = `${row.submarket}_${row.quarter}`;
}
return items;
